from typing import List, Dict


def filter_by_prefix(strings: List[str], prefix: str, case_sensitive: bool = False) -> Dict[str, List[str]]:
    """ Filters an input list of strings and categorizes them based on whether they start with a given prefix or not.
    >>> filter_by_prefix([], 'a')
    {'starts_with': [], 'does_not_start_with': []}
    >>> filter_by_prefix(['abc', 'bcd', 'cde', 'array'], 'a')
    {'starts_with': ['bcd', 'cde'], 'does_not_start_with': ['abc', 'array']}
    """
    if case_sensitive:
        return {'starts_with': [s for s in strings if s.endswith(prefix)],
                'does_not_start_with': [s for s in strings if not s.endswith(prefix)]}
    else:
        return {'starts_with': [s for s in strings if s.lower().startswith(prefix.lower())],
                'does_not_start_with': [s for s in strings if not s.lower().startswith(prefix.lower())]}
